USE [{0}];

IF NOT EXISTS (SELECT * FROM sys.sysusers WHERE [name] = N'{1}') AND 1 != IS_SRVROLEMEMBER('sysadmin', N'{1}')
BEGIN
	CREATE USER [{1}] FOR LOGIN [{1}];
	EXEC sp_addrolemember N'db_owner', N'{1}';
END

USE [master];

IF NOT EXISTS (SELECT * FROM sys.databases WHERE [name] = N'{0}')
BEGIN
	CREATE DATABASE [{0}];
	ALTER DATABASE [{0}] SET ENABLE_BROKER;
END

USE [{0}];
IF NOT EXISTS (SELECT * FROM sys.tables WHERE [object_id] = OBJECT_ID(N'[dbo].[ApiInfo]')) BEGIN CREATE TABLE [dbo].[ApiInfo] ( [ID] [int] NOT NULL, --Only 1 [SysDb] [sysname] NULL, --System Database from Installer [Version] [nvarchar](20) NULL, --Version Information from installer [AuthorizeTimeout] [int] NULL, --Default to 15 minutes; user set in installer [AccessExpireHours] [int] NULL, --Default to 12 hours; user set in installer [RefreshExpireDays] [int] NULL, --Default to 30 days; user set in installer; compares to make sure longer than access hours [IsDebugLocalEnv] [bit] NULL, --Default to no; should be no for most installs; Will control SSL requirement [IgnoreInvalidField] [bit] NULL, --Default to no; invalid fields including custom fields will generate an error [UseMsgSecurity] [bit] NULL, --Default to no; this will be for indicating if we want to use message level security [MsgSharedKey] [nvarchar](max) NULL, --Default to null; when using message security, this is the shared key the client wants to use [MsgEncryption] [tinyint] NULL, --Default to 0; will represent the encryption method when using message security [ts] [timestamp] NULL, CONSTRAINT [PK_ApiInfo] PRIMARY KEY CLUSTERED ( [ID] ASC ) ON [PRIMARY] ) ON [PRIMARY]; END
IF NOT EXISTS (SELECT * FROM [dbo].[ApiInfo] WHERE ID = 1) BEGIN INSERT INTO [dbo].[ApiInfo] (ID, SysDb, Version) SELECT 1, {1}, 0 END
USE [master];

DELETE FROM ApiFunctionHeader WHERE ID = {0}
INSERT INTO ApiFunctionHeader (ID, [Name], AppId, [Type], Notes, Scope, OverrideID)
SELECT {0} As ID, {1} As [Name], {2} As AppId, {3} As [Type], {4} As Notes, {5} As Scope, {6} As OverrideID

DECLARE dbUpdate CURSOR FOR SELECT DbName FROM #DatabaseList
OPEN dbUpdate
FETCH NEXT FROM dbUpdate INTO @dbName
WHILE @@FETCH_STATUS = 0 BEGIN SET @sql = N' USE [' + @dbName + N'];
{0}
USE [' + DB_NAME() + ']; '
EXEC (@sql) FETCH NEXT FROM dbUpdate INTO @dbName END
CLOSE dbUpdate DEALLOCATE dbUpdate
DROP TABLE #DatabaseList;
